INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00207', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關警察機關執行通訊保障及監察法相關敍述，下列何者正確？', '["對於涉及製造、販賣毒品案件3名犯罪嫌疑人，可以聲請1張通訊監察書為之", "各級法院及檢察署之通訊監察投單作業應由刑事警察局通訊監察科為之", "人口販運案件之通訊監察期間，每次不得逾30天", "執行機關應至少每10天派員取回監錄內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00208', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '司法警察官或司法警察，雖無搜索票，得逕行搜索住宅或其他處所，對於逕行搜索執行，下列敍 述何者最正確？', '["應於執行後3日內，將搜索扣押筆錄，以密件封緘，並於信封上註明逕行搜索，函報該管檢察 官，由檢察官再向法院陳報", "因追緝現行犯，而實施逕行搜索時，可以開啟藏匿處室內之保險櫃", "因室內音樂及叫囂音量過大，頻遭民眾檢舉之處所，可以實施逕行搜索", "檢察官依刑事訴訟法第131條第2項指揮警察人員執行逕行搜索，應請其簽發指揮書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00209', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '偵查員甲在某日10時，在郊區逮捕乙，因塞車故於12時，方帶回分局偵查隊製作筆錄，乙表示 要請辯護人到場，等候至15時辯護人到場，辯護人並與犯罪嫌疑人接見至16時，始開始詢問製 作筆錄。甲因身體不適於17時上廁所至18時，又因已屬於夜間，詢問中止，至翌日6時黎明， 警察復於8時開始詢問。請問依據刑事訴訟法第93條之1不予計入之時間共多少小時？', '["5小時", "18小時", "19小時", "20小時"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00210', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關「警察人員與特定對象接觸交往規定」之實施，下列何者正確？', '["警察人員出席一般婚喜慶時，巧遇特定對象，雖無接觸，亦應將接觸經過情形填報交往報告表 陳核", "因公務需與特定對象接觸交往實施後2日內，應將接觸交往經過填報特定對象接觸交往報告表 陳核", "掃黑專責人員執行情蒐、檢肅工作，應於專案前即預先報准，方得實施", "經撤銷註記之幫派組合成員非屬本規定之特定對象"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00211', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警察機關為獎勵民眾提供線索相關規定，下列何者正確？', '["如民眾不願出示真實姓名者，可同意其使用化名、代號或暗語為連絡記號", "民眾提供犯罪線索，無論係書面或口頭紀錄資料，均須附錄於案卷", "公務員執行職務知有犯罪嫌疑而檢舉，亦可給與獎金", "民眾提供具體犯罪線索，因逮捕現行犯或協助緝獲逃犯情節重大者，得專案核發獎金，並得請 發愛群獎章、榮譽章"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00212', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '毒品危害防制條例中，將毒品依據其成癮性、濫用性及對社會危害性分為四級管制，請問下列何 者非屬於第二級毒品？', '["丙泊酚", "LSD（麥角二乙胺）", "PMMA（甲氧基甲基安非他命）", "大麻"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00213', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '甲（現住地於臺北市南港分局）在手機中瀏覽網頁時，加入乙（戶籍地為臺中市豐原分局）所成 立之投資群組，經銀行轉帳200萬（人頭帳戶所有人之戶籍地為彰化縣彰化分局），甲又在臺北 市大安分局轄內面交50萬給出面取款之車手丙，甲發覺受騙向臺北市大安分局報案，則有關本 案之刑事案件之管轄責任應為下列何者？', '["臺北市南港分局", "臺中市豐原分局", "彰化縣彰化分局", "臺北市大安分局"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00214', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警察機關偵辦刑案及處理新聞遵守偵查不公開之相關規定，下列何者錯誤？', '["各機關應劃定採訪禁制區", "案件係由檢察官指揮者，若發布新聞應先徵詢地檢署之意見", "警察局每年應針對所屬實施2小時以上之偵查不公開規定及缺失案例檢討課程", "各警察機關偵查不公開檢討小組，應每半年召開檢討會，檢討該機關新聞有無違反規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00215', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '重大刑案及特殊刑案之通報規定，下列何者正確？', '["受理報案，應於被害人完成筆錄後1小時內填輸通報單", "各警察局應由勤務指揮中心、督察科、人事室成立110報案複查小組", "破獲他轄未通報之案件，應通報發生地轄區分局，由發生地轄區單位填輸發生通報單", "刑案紀錄表應於案件發生及破獲後96小時內填輸，逾時為遲報"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00216', 'police-8b7f1efc', 'police-8b7f1efc-moex-113-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '下列何者非屬於兒童及少年性剝削防制條例中之兒童或少年性剝削行為？', '["使兒童或少年為有對價之猥褻行為", "使兒童或少年坐檯陪酒", "拍攝、製造或販賣兒童或少年之性影像", "酒店老闆攜帶其年幼子女至酒店寫作業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:13+00:00", "source_pdf_sha1": "63b93b23415f", "answer_pdf_sha1": "17d67fbe41eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "501", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
